  return {
    data: {
      timer: null
    },
    attached() {
      // 启动定时器
      this.timer = setInterval(() => {
        console.log('定时任务执行');
      }, 1000);
    },
    detached() {
      // 清理定时器
      if(this.timer) {
        clearInterval(this.timer);
        this.timer = null;
      }
    }
  };
};
